INSERT INTO "PhaseMessages" ("Phase", "Message", "MessageType") VALUES
-- Fase Menstrual (0)
(0, 'Your brain’s left and right hemispheres are communicating more intensely right now, making this the absolute best time for deep reflection and analytical review. Skip the high-stress brainstorming sessions and use today to evaluate recent projects, journal, or organize your thoughts. Your focus is internal—trust your intuition.', 1),
(0, 'With your hormone levels at their lowest baseline, your mental energy is best spent on low-bandwidth, solo tasks. Don’t force yourself to be the loudest voice in the room today. Instead, clear out your inbox, tie up loose administrative ends, and give yourself permission to log off early. Protection of your peace is priority number one.', 1),

-- Fase Folicular (1)
(1, 'As estrogen climbs, it triggers a surge of cortisol and dopamine in your brain, spiking your curiosity and readiness to learn. This is your mental spring. Your focus is exceptionally sharp, making it the perfect window to map out new projects, learn a complex skill, or brainstorm big, audacious goals. If you have been putting off a difficult task, tackle it today.', 1),
(1, 'Your cognitive flexibility and verbal fluency are getting a major upgrade this week. You will find it easier to articulate complex ideas, pitch new strategies, and collaborate with teammates. Direct your focus toward networking, scheduling important meetings, or starting fresh initiatives while your mental momentum is at its peak', 1),

-- Fase Ovulatoria (2)
(2, 'Estrogen and testosterone are peaking simultaneously, unlocking your highest levels of confidence, charisma, and mental stamina. Your focus is entirely external and action-oriented. This is the optimal time to deliver a major presentation, negotiate a deal, or step into the spotlight. You have the verbal precision and magnetism to lead the room.', 1),
(2, 'The hormonal mix in your system right now makes you highly receptive to social cues and incredibly empathetic. Your focus should be on community, deep networking, and strengthening relationships. Whether you are leading a team workshop or hosting a dinner with friends, your communication skills are firing on all cylinders.', 1),

-- Fase Lútea (3)
(3, 'Progesterone is stepping in to calm your nervous system, shifting your mindset from high-energy brainstorming to meticulous execution. Your focus is deeply detail-oriented right now. Use this grounding energy to audit ongoing work, balance budgets, edit written content, and organize your physical space before your energy begins to dip.', 1),
(3, 'As your hormone levels begin their pre-period descent, you might notice your tolerance for noise, clutter, and extra meetings dropping. Your focus is telling you to tie up loose ends rather than starting anything new. Protect your calendar, decline non-essential tasks, and focus on finishing what’s already on your plate.', 1);
